     1→/*
     2→ * sin() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly sin  (test_sin_opt.elf)
     6→ *   2. Linked with toolchain's default sin       (test_sin_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→#ifdef EN_PERF
    16→#define PF_COUNTER
    17→#include "nds_pfcounter.h"
    18→#endif
    19→
    20→static inline uint64_t d2u(double d)
    21→{
    22→    union { double d; uint64_t u; } x;
    23→    x.d = d;
    24→    return x.u;
    25→}
    26→
    27→static inline double u2d(uint64_t u)
    28→{
    29→    union { double d; uint64_t u; } x;
    30→    x.u = u;
    31→    return x.d;
    32→}
    33→
    34→#ifndef EN_PERF
    35→static void emit(double x)
    36→{
    37→    double r = sin(x);
    38→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    39→}
    40→
    41→static void emit_u(uint64_t bits)
    42→{
    43→    emit(u2d(bits));
    44→}
    45→
    46→/* ------------------------------------------------------------------ */
    47→/* Test points                                                         */
    48→/* ------------------------------------------------------------------ */
    49→
    50→/* 1. Special values */
    51→static void test_special(void)
    52→{
    53→    /* Zeros */
    54→    emit(0.0);
    55→    emit(-0.0);
    56→
    57→    /* NaN */
    58→    emit_u(0x7ff8000000000000ULL); /* qNaN */
    59→    emit_u(0x7ff0000000000001ULL); /* sNaN */
    60→    emit_u(0xfff8000000000000ULL); /* -NaN */
    61→
    62→    /* Infinity */
    63→    emit_u(0x7ff0000000000000ULL); /* +Inf */
    64→    emit_u(0xfff0000000000000ULL); /* -Inf */
    65→}
    66→
    67→/* 2. Tiny values: sin(x) ~ x */
    68→static void test_tiny(void)
    69→{
    70→    emit_u(0x0000000000000001ULL); /* min denorm */
    71→    emit_u(0x8000000000000001ULL);
    72→    emit_u(0x0008000000000000ULL); /* mid denorm */
    73→    emit_u(0x8008000000000000ULL);
    74→    emit_u(0x000fffffffffffffULL); /* max denorm */
    75→    emit_u(0x800fffffffffffffULL);
    76→    emit(DBL_MIN);
    77→    emit(-DBL_MIN);
    78→    emit(1.0e-200);
    79→    emit(-1.0e-200);
    80→}
    81→
    82→/* 3. Known mathematical values */
    83→static void test_known(void)
    84→{
    85→    double pi   = 3.14159265358979323846;
    86→    double pi_2 = 1.57079632679489661923;
    87→    double pi_3 = 1.04719755119659774615;
    88→    double pi_4 = 0.78539816339744830962;
    89→    double pi_6 = 0.52359877559829887308;
    90→
    91→    emit(pi_6);
    92→    emit(pi_4);
    93→    emit(pi_3);
    94→    emit(pi_2);
    95→    emit(pi);
    96→    emit(2.0 * pi);
    97→    emit(-pi_6);
    98→    emit(-pi_4);
    99→    emit(-pi_2);
   100→    emit(-pi);
   101→    emit(3.0 * pi_2);
   102→    emit(pi_2 + 0.001);
   103→    emit(pi + 0.001);
   104→    emit(pi - 0.001);
   105→}
   106→
   107→/* 4. Large arguments */
   108→static void test_large(void)
   109→{
   110→    double vals[] = {
   111→        10.0, 100.0, 1000.0, 100000.0, 1000000.0,
   112→        -10.0, -1000.0,
   113→        3.14159265 * 100.0,
   114→        3.14159265 * 1000.0,
   115→        1.0e10, 1.0e20,
   116→        -1.0e10, -1.0e20,
   117→        DBL_MAX, -DBL_MAX,
   118→    };
   119→    int n = sizeof(vals) / sizeof(vals[0]);
   120→    for (int i = 0; i < n; i++)
   121→        emit(vals[i]);
   122→}
   123→
   124→/* 5. Quadrant transitions */
   125→static void test_quadrant(void)
   126→{
   127→    double pi_2 = 1.5707963267948966;
   128→    double offsets[] = { -1e-5, 0.0, 1e-5 };
   129→    int noff = sizeof(offsets) / sizeof(offsets[0]);
   130→
   131→    for (int k = 1; k <= 8; k++) {
   132→        double boundary = (double)k * pi_2;
   133→        for (int j = 0; j < noff; j++)
   134→            emit(boundary + offsets[j]);
   135→    }
   136→}
   137→
   138→/* 6. Worst-case argument reduction */
   139→static void test_hard(void)
   140→{
   141→    double cases[] = {
   142→        u2d(0x400921fb54442d18ULL), /* pi as double */
   143→        u2d(0x401921fb54442d18ULL), /* 2*pi as double */
   144→        u2d(0x4096cbe3f9990046ULL), /* 3*pi/2 */
   145→        4.0, 16.0, 64.0, 256.0,
   146→    };
   147→    int n = sizeof(cases) / sizeof(cases[0]);
   148→    for (int i = 0; i < n; i++) {
   149→        emit(cases[i]);
   150→        emit(-cases[i]);
   151→    }
   152→}
   153→
   154→/* 7. Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
   155→static void test_sweep(void)
   156→{
   157→    double hi = 4.0 * 3.14159265358979323846;
   158→    int nsteps = 200;
   159→    double step = hi / (double)nsteps;
   160→
   161→    /* [0, 4*pi] */
   162→    for (int i = 0; i <= nsteps; i++)
   163→        emit((double)i * step);
   164→
   165→    /* [-4*pi, 0] */
   166→    for (int i = 0; i <= nsteps; i++)
   167→        emit(-hi + (double)i * step);
   168→}
   169→
   170→/* 8. Sample [0, pi/4] every 4503599627370496 ULP (~200 cases) */
   171→static void test_exhaustive_small(void)
   172→{
   173→    uint64_t end = 0x3fe921fb54442d18ULL; /* pi/4 */
   174→    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
   175→        emit_u(b);
   176→}
   177→
   178→/* 9. Random sweep: 300 evenly spaced inputs */
   179→static void test_random_300(void)
   180→{
   181→    double lo = -6.283185307179586;  /* -2*pi */
   182→    double hi =  6.283185307179586;  /* +2*pi */
   183→    int n = 300;
   184→    for (int i = 0; i < n; i++) {
   185→        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
   186→        emit(x);
   187→    }
   188→}
   189→#endif
   190→
   191→/* ------------------------------------------------------------------ */
   192→
   193→#ifdef EN_PERF
   194→/*
   195→ * perf(x) -- exercise the hot kernel path N times and print the result.
   196→ *
   197→ * Critical path for sin():
   198→ *   __gf_dpreduct  (argument reduction)
   199→ *   -> __gf_exmul  (extended-precision multiply)
   200→ *   -> __gf_sigmax(__gf_dpsincon, degree 5)  (polynomial kernel)
   201→ *   -> __gf_exmul  (scale result)
   202→ *
   203→ * This path is taken when the reduced quadrant index q satisfies
   204→ * (q-1)&2 != 0, i.e. q == 0 or q == 3.  x = 1.0 falls in quadrant 0.
   205→ */
   206→static void perf(double x)
   207→{
   208→    volatile double acc = 0.0;
   209→    startPFM;
   210→    for (int i = 0; i < 100; i++)
   211→        acc += sin(x+i);
   212→    stopPFM;
   213→    readResult();
   214→    printf("perf %016llx: %016llx\n",
   215→           (unsigned long long)d2u(x),
   216→           (unsigned long long)d2u((double)acc));
   217→}
   218→#endif /* EN_PERF */
   219→
   220→/* ------------------------------------------------------------------ */
   221→
   222→int main(void)
   223→{
   224→#ifdef EN_PERF
   225→    perf(1.0); /* quadrant 0: hits sin-polynomial kernel path */
   226→#else
   227→    test_special();
   228→    test_tiny();
   229→    test_known();
   230→    test_large();
   231→    test_quadrant();
   232→    test_hard();
   233→    test_sweep();
   234→    test_exhaustive_small();
   235→    test_random_300();
   236→#endif
   237→    return 0;
   238→}
